function _confirmDestructive(actionLabel){
  if(!confirm(actionLabel+'\n\nгҒ“гҒ®ж“ҚдҪңгҒҜеҸ–гӮҠж¶ҲгҒӣгҒҫгҒӣгӮ“гҖӮжң¬еҪ“гҒ«е®ҹиЎҢгҒ—гҒҫгҒҷгҒӢ?')) return false;
  var ans = prompt('зўәиӘҚгҒ®гҒҹгӮҒ "DELETE" гҒЁе…ҘеҠӣгҒ—гҒҰгҒҸгҒ гҒ•гҒ„\nпјҲгӮӯгғЈгғігӮ»гғ«гҒҷгӮӢгҒЁдёӯжӯўпјү', '');
  if(ans !== 'DELETE'){
    alert('е…ҘеҠӣгҒҢдёҖиҮҙгҒ—гҒӘгҒ„гҒҹгӮҒдёӯжӯўгҒ—гҒҫгҒ—гҒҹ');
    return false;
  }
  return true;
}

function clearHistory(){
  // B14 (2026-05-16): ж—§д»•ж§ҳгҒҜ LS еүҠйҷӨгҒ®гҒҝгҒ§еҶҚжҸҸз”»гҒӣгҒҡгҖҒз”»йқўгҒ«еҸӨгҒ„ render гҒҢж®ӢгӮҠ
  //   гҖҢеүҠйҷӨгҒ•гӮҢгҒӘгҒ„гҖҚгҒЁгғҰгғјгӮ¶гҒҢиӘӨиӘҚгҒ—гҒҰгҒ„гҒҹгҖӮrebuildDB гҒЁеҗҢж§ҳгҒ« location.reload()
  //   гҒ§е®Ңе…ЁгғӘгғ•гғ¬гғғгӮ·гғҘгҖӮгҒҫгҒҹ migration flag / corrupt backup гӮӮеҗҢжҷӮжҺғйҷӨгҒ—гҖҒ
  //   е®Ңе…ЁгӮҜгғӘгғјгғізҠ¶ж…ӢгҒӢгӮүеҶҚиө·еӢ•гҒҷгӮӢгҖӮ
  if(_confirmDestructive('жҲҗзёҫеұҘжӯҙгӮ’е…ЁгҒҰеүҠйҷӨгҒ—гҒҫгҒҷгҒӢ?')){
    try { localStorage.removeItem('boatrace_history'); } catch(_){}
    // й–ўйҖЈ key гӮӮжҺғйҷӨ
    try { localStorage.removeItem('boatrace_history_migrated_v21'); } catch(_){}
    try {
      // corrupt backup гҒ®жҺғйҷӨ
      var _toRm = [];
      for(var i=0;i<localStorage.length;i++){
        var k = localStorage.key(i);
        if(k && k.indexOf('boatrace_history__corrupt_') >= 0) _toRm.push(k);
      }
      _toRm.forEach(function(k){ try { localStorage.removeItem(k); } catch(_){} });
    } catch(_){}
    alert('еұҘжӯҙгӮ’еүҠйҷӨгҒ—гҒҫгҒ—гҒҹгҖӮз”»йқўгӮ’еҶҚиӘӯиҫјгҒ—гҒҫгҒҷгҖӮ');
    location.reload();
  }
}

