function _loadErrorLog(){
  try{ var raw=localStorage.getItem('boatrace_errors'); if(!raw) return [];
       var v=JSON.parse(raw); return Array.isArray(v)?v:[]; }
  catch(_){ return []; }
}

function showErrorLog(){
  var buf=_loadErrorLog();
  if(!buf.length){ alert('гӮЁгғ©гғјгғӯгӮ°гҒҜз©әгҒ§гҒҷ'); return; }
  // B15 (2026-05-17): diag_* (иЁәж–ӯгғӯгӮ°) гӮ’ default йқһиЎЁзӨәгҒ«гҒ—гҒҰгҖҢгӮЁгғ©гғјгҒҢеҮәгҒҰгҒ„гӮӢгҖҚ
  //   иӘӨиӘҚгӮ’йҳІгҒҗгҖӮзңҹгҒ®гӮЁгғ©гғј (error/reject/warn/worker_error) гҒ®гҒҝгӮ’зӣ®з«ӢгҒҹгҒӣгҖҒ
  //   иЁәж–ӯгғӯгӮ°ж•°гҒҜ footer гҒ«еҶ…иЁіиЎЁзӨәгҖӮи©ізҙ°гҒҜгҖҢгӮігғ”гғјгҖҚгғңгӮҝгғігҒ§ JSON е…Ёж–ҮгӮ’еҸ–еҫ—еҸҜиғҪгҖӮ
  var errs = [], diags = [];
  buf.forEach(function(e){
    var t = e.type || '';
    if(t.indexOf('diag_') === 0) diags.push(e);
    else errs.push(e);
  });
  if(errs.length === 0){
    var diagSummary = {};
    diags.forEach(function(d){ var t=d.type||'?'; diagSummary[t]=(diagSummary[t]||0)+1; });
    var summaryStr = Object.keys(diagSummary).map(function(k){return k+'='+diagSummary[k];}).join(', ');
    alert('вң… гӮЁгғ©гғјгҒҜгҒӮгӮҠгҒҫгҒӣгӮ“гҖӮ\n\nпјҲиЁәж–ӯгғӯгӮ° '+diags.length+' д»¶: '+summaryStr+'пјү\n'
        + 'вҖ» иЁәж–ӯгғӯгӮ°гҒҜгӮўгғ—гғӘжӯЈеёёеӢ•дҪңгҒ®зӮ№жӨңиЁҳйҢІгҒ§гҒҷгҖӮж°—гҒ«гҒӘгӮӢе ҙеҗҲгҒҜгҖҢгӮігғ”гғјгҖҚгҒ§е…Ёж–ҮзўәиӘҚгҒ§гҒҚгҒҫгҒҷгҖӮ');
    return;
  }
  var lines = errs.slice(-30).map(function(e){
    var head = '['+(e.iso||new Date(e.ts).toISOString()).slice(11,19)+'] '+(e.type||'?')+': '+(e.msg||'');
    if(e.src) head += ' @ '+e.src+':'+(e.line||0);
    if(e.type === 'worker_error'){
      head += ' target='+(e.target||'(none)')+' eventType='+(e.eventType||'?');
    }
    return head;
  });
  var footer = '';
  if(diags.length > 0){
    footer = '\n\n[+'+diags.length+' д»¶гҒ®иЁәж–ӯгғӯгӮ° (жӯЈеёёеӢ•дҪңгҒ®иЁҳйҢІ) гӮ’йқһиЎЁзӨәгҖӮи©ізҙ°гҒҜгҖҢгӮігғ”гғјгҖҚгғңгӮҝгғігҒ§зўәиӘҚеҸҜ]';
  }
  alert('вҡ  гӮЁгғ©гғј '+errs.length+' д»¶ (зӣҙиҝ‘ '+lines.length+' д»¶иЎЁзӨә):\n\n'+lines.join('\n')+footer);
}

function copyErrorLog(){
  var buf=_loadErrorLog();
  var text=JSON.stringify(buf, null, 2);
  if(navigator.clipboard && navigator.clipboard.writeText){
    navigator.clipboard.writeText(text).then(function(){ alert('гӮҜгғӘгғғгғ—гғңгғјгғүгҒ«гӮігғ”гғјгҒ—гҒҫгҒ—гҒҹ ('+buf.length+'д»¶)'); },
      function(e){ alert('гӮігғ”гғјеӨұж•—: '+e); });
  } else {
    // гғ•гӮ©гғјгғ«гғҗгғғгӮҜ: textarea гӮ’д»ӢгҒ—гҒҹ execCommand
    var ta=document.createElement('textarea'); ta.value=text; document.body.appendChild(ta); ta.select();
    try{ document.execCommand('copy'); alert('гӮігғ”гғјгҒ—гҒҫгҒ—гҒҹ ('+buf.length+'д»¶)'); }
    catch(e){ alert('гӮігғ”гғјеӨұж•—: '+e); }
    finally{ document.body.removeChild(ta); }
  }
}

